# Bold: U+1D400-1D433 (A-Z), U+1D41A-1D433 (a-z)
def to_math_bold(s):
    r = ''
    for c in s:
        if 'a' <= c <= 'z':
            r += chr(0x1d41a + ord(c) - ord('a'))
        elif 'A' <= c <= 'Z':
            r += chr(0x1d400 + ord(c) - ord('A'))
        else:
