    return r

# Italic: U+1D434-1D467
def to_math_italic(s):
    r = ''
    for c in s:
        if 'a' <= c <= 'z':
            # italic has a gap at 'h' (U+210E)
            if c == 'h':
                r += '\u210e'
            else:
                r += chr(0x1d44e + ord(c) - ord('a'))
        elif 'A' <= c <= 'Z':
            r += chr(0x1d434 + ord(c) - ord('A'))
        else:
            r += c
    return r

